css:
:root{
  --bg:#0c0b10;
  --bg-2:#14121b;
  --panel:#1a1722;
  --line:#2a2533;
  --text:#ece8f1;
  --muted:#9a93a7;
  --gold:#c9a24b;
  --gold-soft:#e0c06f;
  --danger:#c8584f;
  --maxw:1180px;
  --serif:'Playfair Display',Georgia,serif;
  --sans:'Inter',system-ui,-apple-system,Segoe UI,Roboto,sans-serif;
}
*{box-sizing:border-box}
html,body{margin:0;padding:0}
body{
  background:
    radial-gradient(1200px 600px at 80% -10%, rgba(201,162,75,.10), transparent 60%),
    radial-gradient(900px 500px at -10% 10%, rgba(201,162,75,.06), transparent 60%),
    var(--bg);
  color:var(--text);
  font-family:var(--sans);
  line-height:1.6;
  -webkit-font-smoothing:antialiased;
}
a{color:inherit;text-decoration:none}
.wrap{max-width:var(--maxw);margin:0 auto;padding:0 24px}

/* Nav */
.topnav{
  position:sticky;top:0;z-index:30;
  background:rgba(12,11,16,.82);
  backdrop-filter:blur(12px);
  border-bottom:1px solid var(--line);
}
.nav-inner{display:flex;align-items:center;gap:28px;height:68px}
.brand{
  font-family:var(--serif);font-weight:900;letter-spacing:.14em;
  font-size:20px;color:var(--text);text-transform:uppercase;
}
.brand span{color:var(--gold);font-weight:500;letter-spacing:.08em;font-size:12px;margin-left:8px}
.brand.small{font-size:16px}
.nav-links{display:flex;gap:22px;margin-left:auto;flex-wrap:wrap}
.nav-links a{color:var(--muted);font-size:13px;letter-spacing:.06em;text-transform:uppercase;font-weight:500;transition:color .2s}
.nav-links a:hover{color:var(--gold-soft)}
.admin-link{
  margin-left:8px;color:var(--gold)!important;border:1px solid var(--line);
  padding:7px 14px;border-radius:999px;font-size:12px;text-transform:uppercase;letter-spacing:.08em;
}
.admin-link:hover{border-color:var(--gold)}

/* Masthead */
.masthead{padding:64px 24px 28px}
.kicker{color:var(--gold);text-transform:uppercase;letter-spacing:.28em;font-size:12px;font-weight:600;margin:0 0 12px}
.masthead h1{font-family:var(--serif);font-weight:900;font-size:clamp(40px,6vw,76px);line-height:1.02;margin:0;letter-spacing:-.01em}

/* Hero */
.hero{display:grid;grid-template-columns:1fr 1fr;gap:26px;padding-bottom:20px}
.section-title{font-family:var(--serif);font-size:26px;font-weight:700;margin:40px 0 22px;padding-bottom:12px;border-bottom:1px solid var(--line)}

/* Grid + cards */
.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:26px;padding-bottom:30px}
.card{background:var(--panel);border:1px solid var(--line);border-radius:16px;overflow:hidden;display:flex;flex-direction:column;transition:transform .25s,border-color .25s}
.card:hover{transform:translateY(-4px);border-color:rgba(201,162,75,.5)}
.card-cover{display:block;position:relative;aspect-ratio:16/10;background-size:cover}
.card-big .card-cover{aspect-ratio:16/9}
.cat-chip{
  position:absolute;top:14px;left:14px;background:rgba(12,11,16,.78);
  color:var(--gold-soft);font-size:11px;letter-spacing:.12em;text-transform:uppercase;
  font-weight:600;padding:6px 12px;border-radius:999px;border:1px solid rgba(201,162,75,.35);
}
.cat-chip.dark{position:static;display:inline-block;margin-bottom:18px}
.card-body{padding:20px 22px 24px}
.card h3{font-family:var(--serif);font-size:21px;line-height:1.25;margin:0 0 10px;font-weight:700}
.card-big h3{font-size:28px}
.card h3 a:hover{color:var(--gold-soft)}
.excerpt{color:var(--muted);font-size:14.5px;margin:0 0 16px}
.meta{color:var(--gold);font-size:12px;letter-spacing:.05em;text-transform:uppercase}

/* Article */
.post-cover{height:clamp(220px,42vh,440px);background-size:cover;background-position:center;border-bottom:1px solid var(--line)}
.post-inner{max-width:760px;padding-top:42px;padding-bottom:30px}
.post-inner h1{font-family:var(--serif);font-size:clamp(32px,5vw,52px);line-height:1.08;margin:0 0 18px;font-weight:900}
.post-meta{color:var(--gold);text-transform:uppercase;letter-spacing:.08em;font-size:12.5px;margin-bottom:34px}
.post-body{font-size:18.5px;line-height:1.8}
.post-body p{margin:0 0 24px}
.post-body p:first-of-type{font-size:21px;color:#fff}
.back{display:inline-block;margin-top:18px;color:var(--gold);font-size:14px;letter-spacing:.04em}
.back:hover{color:var(--gold-soft)}
.related{padding-bottom:60px}

.empty{color:var(--muted);padding:30px 0}
.empty a,.post-body a{color:var(--gold-soft)}

/* Footer */
.site-footer{border-top:1px solid var(--line);margin-top:50px;padding:38px 0;background:var(--bg-2)}
.site-footer .wrap{display:flex;align-items:center;gap:18px;flex-wrap:wrap}
.site-footer p{color:var(--muted);font-size:13px;margin:0}

/* ---------- Admin ---------- */
body.admin{background:var(--bg-2)}
.admin-nav{background:rgba(20,18,27,.9)}
.admin-main{padding:38px 24px 80px}
.admin-head{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:24px;gap:16px;flex-wrap:wrap}
.admin-head h1{font-family:var(--serif);font-size:34px;margin:0}
.muted{color:var(--muted);font-size:13px;margin:4px 0 0}
.btn{
  background:var(--gold);color:#1a1406;border:none;border-radius:10px;
  padding:11px 18px;font-weight:600;font-size:14px;cursor:pointer;
  font-family:var(--sans);display:inline-block;transition:filter .2s
}
.btn:hover{filter:brightness(1.08)}
.btn.ghost{background:transparent;color:var(--text);border:1px solid var(--line)}
.btn.small{padding:7px 12px;font-size:12.5px}
.btn.danger{background:transparent;color:var(--danger);border:1px solid rgba(200,88,79,.4)}
.btn.danger:hover{background:rgba(200,88,79,.12)}

.admin-table{width:100%;border-collapse:collapse;background:var(--panel);border:1px solid var(--line);border-radius:14px;overflow:hidden}
.admin-table th{text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.1em;color:var(--muted);padding:14px 18px;border-bottom:1px solid var(--line)}
.admin-table td{padding:16px 18px;border-bottom:1px solid var(--line);vertical-align:middle;font-size:14px}
.admin-table tr:last-child td{border-bottom:none}
.admin-table .actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap}
.admin-table form{margin:0}
.badge{background:rgba(201,162,75,.15);color:var(--gold-soft);border:1px solid rgba(201,162,75,.3);font-size:11px;padding:4px 10px;border-radius:999px;text-transform:uppercase;letter-spacing:.06em}

.post-form{background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:28px;max-width:820px}
.post-form label{display:block;margin-bottom:18px;font-size:13px;color:var(--muted);font-weight:500}
.post-form .row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px}
.post-form input,.post-form textarea{
  width:100%;margin-top:7px;background:var(--bg);border:1px solid var(--line);
  border-radius:9px;color:var(--text);padding:11px 13px;font-family:var(--sans);font-size:15px
}
.post-form textarea{resize:vertical;line-height:1.6}
.post-form input:focus,.post-form textarea:focus{outline:none;border-color:var(--gold)}
.post-form .check{display:flex;align-items:center;gap:10px;color:var(--text)}
.post-form .check input{width:auto;margin:0}
.post-form .opt{color:var(--muted);font-weight:400;font-size:11px;text-transform:none;letter-spacing:0}
.cover-picker{display:flex;flex-wrap:wrap;gap:10px;margin:2px 0 18px}
.cover-opt{width:104px;height:60px;border-radius:9px;border:2px solid var(--line);background-size:cover;background-position:center;cursor:pointer;padding:0;color:var(--muted);font-size:11px;font-family:var(--sans)}
.cover-opt.none{background:var(--bg);display:flex;align-items:center;justify-content:center}
.cover-opt:hover{border-color:rgba(201,162,75,.6)}
.cover-opt.selected{border-color:var(--gold);box-shadow:0 0 0 2px rgba(201,162,75,.3)}

.flash{padding:12px 16px;border-radius:10px;margin-bottom:20px;font-size:14px}
.flash.ok{background:rgba(201,162,75,.12);border:1px solid rgba(201,162,75,.35);color:var(--gold-soft)}
.flash.error{background:rgba(200,88,79,.12);border:1px solid rgba(200,88,79,.4);color:#e7a39c}

/* Login */
.login-page{display:flex;align-items:center;justify-content:center;min-height:100vh}
.login-card{background:var(--panel);border:1px solid var(--line);border-radius:18px;padding:38px;width:min(380px,90vw);text-align:center}
.login-card .brand{display:block;margin-bottom:6px}
.login-card label{display:block;text-align:left;margin:22px 0 0;font-size:13px;color:var(--muted)}
.login-card input{width:100%;margin-top:8px;background:var(--bg);border:1px solid var(--line);border-radius:9px;color:var(--text);padding:12px;font-size:15px}
.login-card input:focus{outline:none;border-color:var(--gold)}
.login-card button{width:100%;margin-top:22px}
.login-card .hint{color:var(--muted);font-size:12px;margin:18px 0 0}
.login-card code{color:var(--gold-soft);background:var(--bg);padding:2px 6px;border-radius:5px}

@media(max-width:880px){
  .hero{grid-template-columns:1fr}
  .grid{grid-template-columns:1fr 1fr}
  .post-form .row{grid-template-columns:1fr}
}
@media(max-width:560px){
  .grid{grid-template-columns:1fr}
  .nav-links{display:none}
}
